import { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { getEventById } from "../services/eventService";
import { getAuthHeaders } from "../services/authService";
import { Card, Button, Form, Row, Col, Spinner, Alert } from "react-bootstrap";

function EventDetailPage() {
  const { eventId } = useParams(); // Lấy eventId từ URL
  const [event, setEvent] = useState(null);
  const [ticketTypes, setTicketTypes] = useState([]);
  const [selectedTicket, setSelectedTicket] = useState(null);
  const [quantity, setQuantity] = useState(1);
  const [error, setError] = useState("");
  const navigate = useNavigate();

  useEffect(() => {
    // Kiểm tra nếu eventId không hợp lệ
    if (!eventId) {
      setError("ID sự kiện không hợp lệ.");
      return;
    }

    const fetchEventDetails = async () => {
      try {
        console.log("Bắt đầu gọi API...");
        const response = await getEventById(eventId); // Gọi API với eventId
        console.log("Dữ liệu sự kiện: ", response); // Kiểm tra dữ liệu trả về

        if (response.data?.success) {
          setEvent(response.data.data);
          setTicketTypes(response.data.data.ticket_types || []);
        } else {
          setError("Không có thông tin sự kiện");
        }
      } catch (err) {
        console.error("Error fetching event details", err);
        setError("Lỗi khi tải sự kiện");
      }
    };

    fetchEventDetails(); // Fetch sự kiện mỗi khi eventId thay đổi
  }, [eventId]); // Đảm bảo fetch lại khi eventId thay đổi

  const handleTicketSelection = (ticketId) => {
    setSelectedTicket(ticketId);
  };

  const handleQuantityChange = (e) => {
    setQuantity(e.target.value);
  };

  const handleAddToCart = () => {
    if (!selectedTicket) {
      alert("Vui lòng chọn loại vé!");
      return;
    }
    // Logic xử lý khi người dùng thêm vé vào giỏ hàng
    console.log("Vé đã chọn:", selectedTicket, "Số lượng:", quantity);
  };

  return (
    <div className="my-5">
      {event ? (
        <div>
          <h2>{event.title}</h2>
          <p>{event.description}</p>
          <h4>Chọn loại vé</h4>
          
          {error && <Alert variant="danger">{error}</Alert>} {/* Hiển thị lỗi nếu có */}

          {ticketTypes.length === 0 ? (
            <p>Không có loại vé nào cho sự kiện này.</p>
          ) : (
            <Row>
              {ticketTypes.map((ticket) => (
                <Col key={ticket.id} md={4}>
                  <Card className="mb-3">
                    <Card.Body>
                      <Card.Title>{ticket.name}</Card.Title>
                      <Card.Text>Giá: {ticket.price} VND</Card.Text>
                      <Form.Check
                        type="radio"
                        label={`Chọn vé ${ticket.name}`}
                        name="ticket"
                        onChange={() => handleTicketSelection(ticket.id)} // Lựa chọn vé
                      />
                      {selectedTicket === ticket.id && (
                        <Form.Group>
                          <Form.Label>Số lượng</Form.Label>
                          <Form.Control
                            type="number"
                            value={quantity}
                            onChange={handleQuantityChange}
                            min={1}
                            max={ticket.quantity_total - ticket.quantity_sold}
                          />
                        </Form.Group>
                      )}
                    </Card.Body>
                  </Card>
                </Col>
              ))}
            </Row>
          )}
          <Button variant="primary" onClick={handleAddToCart}>
            Thêm vào giỏ
          </Button>
        </div>
      ) : (
        <div className="d-flex justify-content-center align-items-center" style={{ height: "100vh" }}>
          <Spinner animation="border" variant="primary" /> {/* Hiển thị spinner khi đang tải */}
        </div>
      )}
    </div>
  );
}

export default EventDetailPage;
